function inferProblems(item){
  const m=(item.movement||'').toLowerCase();
  if(SPECIAL_PROBLEMS[item.id]) return SPECIAL_PROBLEMS[item.id];
  if(m.includes('реализм')||m.includes('натурализм')) return 'личность и общество; социальная среда; деньги и власть; нравственный выбор; типический характер';
  if(m.includes('романтизм')) return 'идеал и действительность; свобода; одиночество; двоемирие; исключительный герой';
  if(m.includes('модернизм')||m.includes('экспрессионизм')) return 'кризис личности; отчуждение; время и память; границы языка; поиск новой формы';
  if(m.includes('постмодернизм')) return 'множественность истины; игра с текстом; память культуры; ирония; границы авторства';
  if(m.includes('символизм')||m.includes('декаданс')) return 'искусство и действительность; тайна мира; кризис языка; красота; одиночество художника';
  if(m.includes('просвещение')) return 'разум и предрассудок; общественный порядок; воспитание; свобода; критика догмы';
  if(m.includes('классицизм')) return 'долг и чувство; честь; общественная норма; разум; конфликт личности и роли';
  if(m.includes('эпос')) return 'героизм; честь; судьба; память рода; человек и коллектив';
  return 'личность и общество; нравственный выбор; свобода и ответственность; историческая среда; поиск смысла';
}

